import json
from collections import defaultdict
from datetime import datetime, timezone


def parse_ts(ts):
    """ISO-8601 string -> datetime. Missing/bad -> very old, so it sorts last."""
    if not ts:
        return datetime.min.replace(tzinfo=timezone.utc)
    try:
        return datetime.fromisoformat(ts.replace("Z", "+00:00"))
    except ValueError:
        return datetime.min.replace(tzinfo=timezone.utc)


def top_k_frequent_errors(path, k=10, recent_first=True):
    """
    Sort errors by:
      1) count      -> highest first  (ALWAYS primary)
      2) timestamp  -> tiebreaker:
                         recent_first=True  -> newest error first
                         recent_first=False -> oldest error first
    """
    counts = defaultdict(int)
    rep_ts = {}   # the timestamp we use to compare tied errors

    with open(path) as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except json.JSONDecodeError:
                continue
            if e.get("logType") != "error":
                continue
            msg = e.get("message")
            if msg is None:
                continue

            ts = e.get("time", "")
            counts[msg] += 1

            # recent_first -> remember the LATEST time this error appeared
            # else         -> remember the EARLIEST time it appeared
            if msg not in rep_ts:
                rep_ts[msg] = ts
            elif recent_first and parse_ts(ts) > parse_ts(rep_ts[msg]):
                rep_ts[msg] = ts
            elif not recent_first and parse_ts(ts) < parse_ts(rep_ts[msg]):
                rep_ts[msg] = ts

    def key(item):
        msg, cnt = item
        t = parse_ts(rep_ts[msg]).timestamp()
        return (-cnt, -t if recent_first else t, msg)

    ordered = sorted(counts.items(), key=key)
    return [(m, c, rep_ts[m]) for m, c in ordered[:k]]


# ---------------- demo ----------------
rows = [
    # Alpha and Bravo BOTH appear twice -> same count = 2 -> tie!
    {"time": "2023-04-01T10:00:00Z", "message": "Bravo", "logType": "error"},
    {"time": "2023-04-01T10:05:00Z", "message": "Bravo", "logType": "error"},
    {"time": "2023-04-01T11:00:00Z", "message": "Alpha", "logType": "error"},
    {"time": "2023-04-01T11:30:00Z", "message": "Alpha", "logType": "error"},
]
with open("demo.log", "w") as f:
    for r in rows:
        f.write(json.dumps(r) + "\n")

print("Both Alpha and Bravo have count = 2 (a tie).")
print("Bravo's newest time = 10:05,  Alpha's newest time = 11:30\n")

print("recent_first=True  (newest error first -> Alpha wins):")
for m, c, t in top_k_frequent_errors("demo.log", recent_first=True):
    print(f"   {m:7} count={c}  ts={t}")

print("\nrecent_first=False (oldest error first -> Bravo wins):")
for m, c, t in top_k_frequent_errors("demo.log", recent_first=False):
    print(f"   {m:7} count={c}  ts={t}")

import json, os, heapq, hashlib, tempfile
from collections import defaultdict
from datetime import datetime, timezone


def parse_ts(ts):
    if not ts:
        return datetime.min.replace(tzinfo=timezone.utc)
    try:
        return datetime.fromisoformat(ts.replace("Z", "+00:00"))
    except ValueError:
        return datetime.min.replace(tzinfo=timezone.utc)


def top_k_external(path, k=10, num_shards=16, recent_first=True):
    """
    Memory-bounded top-k for files whose DISTINCT errors don't fit in RAM.

    Pass 1 (map):    stream file, hash each error message to one of N shard
                     files on disk. Same message -> same shard, guaranteed.
    Pass 2 (reduce): count each shard separately (each fits in memory),
                     keep that shard's local top-k.
    Merge:           combine all shard tops -> global top-k.

    Memory: O(largest shard's distinct count) + O(N_shards * k), not O(D).
    """
    tmpdir = tempfile.mkdtemp(prefix="logshards_")
    shard_paths = [os.path.join(tmpdir, f"shard_{i}.jsonl") for i in range(num_shards)]
    shards = [open(p, "w") for p in shard_paths]

    # ---- Pass 1: partition error lines to shards by hash(message) ----
    with open(path) as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                e = json.loads(line)
            except json.JSONDecodeError:
                continue
            if e.get("logType") != "error":
                continue
            msg = e.get("message")
            if msg is None:
                continue
            h = int(hashlib.md5(msg.encode()).hexdigest(), 16) % num_shards
            shards[h].write(json.dumps({"m": msg, "t": e.get("time", "")}) + "\n")
    for s in shards:
        s.close()

    # ---- Pass 2: count each shard, keep local top-k ----
    def shard_key(item):
        msg, (cnt, ts) = item
        t = parse_ts(ts).timestamp()
        return (-cnt, -t if recent_first else t, msg)

    global_candidates = []
    for sp in shard_paths:
        counts = defaultdict(int)
        rep_ts = {}
        with open(sp) as f:
            for line in f:
                rec = json.loads(line)
                m, ts = rec["m"], rec["t"]
                counts[m] += 1
                if m not in rep_ts:
                    rep_ts[m] = ts
                elif recent_first and parse_ts(ts) > parse_ts(rep_ts[m]):
                    rep_ts[m] = ts
                elif not recent_first and parse_ts(ts) < parse_ts(rep_ts[m]):
                    rep_ts[m] = ts
        items = [(m, (c, rep_ts[m])) for m, c in counts.items()]
        items.sort(key=shard_key)
        global_candidates.extend(items[:k])   # only this shard's top-k survives

    # ---- Merge: global top-k from the shard tops ----
    global_candidates.sort(key=shard_key)
    result = [(m, c, ts) for m, (c, ts) in global_candidates[:k]]

    for sp in shard_paths:
        os.remove(sp)
    os.rmdir(tmpdir)
    return result


# ---------------- test: external result == in-memory truth ----------------
if __name__ == "__main__":
    import random
    random.seed(1)
    errs = [f"Error_{i}" for i in range(200)]
    freq = {m: random.randint(1, 50) for m in errs}
    lines = []
    for m, fq in freq.items():
        for j in range(fq):
            lines.append(json.dumps({
                "time": f"2023-04-01T{j%24:02d}:00:00Z",
                "message": m, "logType": "error"}))
    for _ in range(300):
        lines.append(json.dumps({"time": "2023-04-01T00:00:00Z",
                                 "message": "noise", "logType": "info"}))
    random.shuffle(lines)
    with open("big.log", "w") as f:
        f.write("\n".join(lines) + "\n")

    got = top_k_external("big.log", k=10, num_shards=8)

    # oracle: just count by frequency (ties don't collide here since freqs vary)
    truth = sorted(freq.items(), key=lambda kv: (-kv[1], kv[0]))[:10]
    got_pairs = [(m, c) for m, c, _ in got]

    print("External top-10:")
    for m, c, ts in got:
        print(f"   {m:10} count={c}")
    assert got_pairs == truth, f"\nGOT  {got_pairs}\nWANT {truth}"
    print("\nMatches in-memory oracle. ✅")

